module RefModule(input clk, input rst, input data, output reg [2:0] q);reg [2:0] obf_q_temp;

    always @(posedge clk or negedge rst) begin
        if (rst == 0) begin
            obf_q_temp <= 3'b0;
        end
        else begin
            obf_q_temp <= {obf_q_temp[1:0], data};
        end
    end

    assign q = obf_q_temp;
endmodule
